(function() {
  function fire(key, code, kc) {
    document.dispatchEvent(new KeyboardEvent('keydown', { key: key, code: code, keyCode: kc, which: kc, shiftKey: true, bubbles: true, cancelable: true }));
  }
  // 1) Player Next button (works in playlists and for autoplay-next on watch pages)
  var btn = document.querySelector('.ytp-next-button');
  if (btn instanceof HTMLElement && btn.getAttribute('aria-disabled') !== 'true') { btn.click(); return; }
  // 2) Next item in the playlist panel, by index of the currently-selected item
  var items = Array.prototype.slice.call(document.querySelectorAll('ytd-playlist-panel-video-renderer'));
  var idx = items.findIndex(function(el) { return el.hasAttribute('selected'); });
  if (idx !== -1 && items[idx + 1]) {
    var link = items[idx + 1].querySelector('a#wc-endpoint');
    if (link instanceof HTMLElement) { link.click(); return; }
  }
  // 3) Native YouTube shortcut SHIFT+N (next video / next recommended)
  fire('N', 'KeyN', 78);
})();

(function() {
  function fire(key, code, kc) {
    document.dispatchEvent(new KeyboardEvent('keydown', { key: key, code: code, keyCode: kc, which: kc, shiftKey: true, bubbles: true, cancelable: true }));
  }
  // 1) Player Previous button (present, but disabled outside a playlist)
  var btn = document.querySelector('.ytp-prev-button');
  if (btn instanceof HTMLElement && btn.getAttribute('aria-disabled') !== 'true') { btn.click(); return; }
  // 2) Previous item in the playlist panel, by index of the currently-selected item
  var items = Array.prototype.slice.call(document.querySelectorAll('ytd-playlist-panel-video-renderer'));
  var idx = items.findIndex(function(el) { return el.hasAttribute('selected'); });
  if (idx > 0 && items[idx - 1]) {
    var link = items[idx - 1].querySelector('a#wc-endpoint');
    if (link instanceof HTMLElement) { link.click(); return; }
  }
  // 3) Native YouTube shortcut SHIFT+P (previous video in playlist)
  fire('P', 'KeyP', 80);
})();
